<?phpnamespace App\Http\Resources;use Illuminate\Http\Resources\Json\JsonResource;class CustomWithdrawResource extends JsonResource{    public function toArray($request)    {        $campy = ['network'         => $this->network,                  'campay_acc_no'   => $this->campay_acc_no,                  'campay_acc_name' => $this->campay_acc_name,                  'reference'       => $this->reference];        $bank = [            'iban'      => $this->iban,            'acc_name'  => $this->acc_name,            'address'   => $this->address,            'swift'     => $this->swift,            'reference' => $this->reference,        ];        $data = [            'id'           => $this->id,            'amount'       => $this->amount,            'method'       => $this->method,            'fee'          => $this->fee,            'country'      => $this->country,            'acc_email'    => $this->acc_email,            'status'       => ucfirst($this->status),            'request_date' => $this->created_at        ];        if ($this->method == 'Campay') {            return [...$data, ...$campy];        }        if ($this->method == 'Bank') {            return [...$data, ...$bank];        }        return $data;    }}